public int writeValue(boolean incrIndexAndSetStatusAfter) {
    if (!incrIndexAndSetStatusAfter && _lastWasRoot) {
        setOk();
        return 2;
    }
    boolean gotName;
    switch(_context) {
    case TYPE_ROOT:
        if ((_flags & WRITER_TYPE_MASK) != OBJECT_CONTEXT && (this._next == null || this._next._index < -1)) {
            this._current.append("[]");
            break;
        }
        gotName = false;
        try {
            prepareForObject();
        } catch (IOException e) {
            throw JsonGenerationException.fromThrowable(e);
        }

        break;
    case TYPE_FIELDNAME:
        gotName = true;
    default:
        _valueCount += 1L;
        if (!gotName && this._next != null && this._next._index > -2) {
            ++this._next._index;
            if (this._next._length > 0) {
                append(']');
                reset();
                ++_index;
                return 3;
            }
        } else {
            ++_index;
        }

        return STATUS_NO_CONTENT;
    }

    return this.setOkStateOrNextToken(STATUS_OK_AFTER_WRITEVALUE);
}

